#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-29

# sync-shared-scripts.sh — propagates scripts/_shared/* to consumer skill dirs.
#
# Why this exists: render-spec.mjs is consumed by both /ork:explore and
# /ork:assess. The plugin-build pipeline does `cp -R src/skills/`, so each
# consumer must have its own copy on disk. Maintaining two copies by hand
# created drift (caught in /ork:assess audit). This script makes the
# `_shared/` version the single source of truth and propagates on demand.
#
# Run modes:
#   bash scripts/sync-shared-scripts.sh         # propagate (overwrite consumers)
#   bash scripts/sync-shared-scripts.sh --check # exit 1 if any consumer has drifted

set -euo pipefail

PROJECT_ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"
SHARED_DIR="$PROJECT_ROOT/scripts/_shared"
MODE="${1:-sync}"

# Manifest: canonical name -> consumer paths (pipe-delimited).
# Add new shared scripts here as the codebase grows.
MANIFEST=(
  "render-spec.mjs|src/skills/explore/scripts/render-spec.mjs|src/skills/assess/scripts/render-spec.mjs"
)

DRIFT=0
SYNCED=0

for entry in "${MANIFEST[@]}"; do
  IFS='|' read -ra parts <<< "$entry"
  canonical="${parts[0]}"
  src="$SHARED_DIR/$canonical"

  if [[ ! -f "$src" ]]; then
    echo "FAIL: canonical missing: $src" >&2
    exit 2
  fi

  for ((i=1; i<${#parts[@]}; i++)); do
    consumer_rel="${parts[$i]}"
    consumer="$PROJECT_ROOT/$consumer_rel"
    consumer_dir="$(dirname "$consumer")"

    if [[ "$MODE" == "--check" ]]; then
      if [[ ! -f "$consumer" ]] || ! cmp -s "$src" "$consumer"; then
        echo "DRIFT: $consumer_rel does not match $canonical" >&2
        DRIFT=$((DRIFT + 1))
      fi
    else
      mkdir -p "$consumer_dir"
      if [[ ! -f "$consumer" ]] || ! cmp -s "$src" "$consumer"; then
        cp "$src" "$consumer"
        chmod +x "$consumer"
        echo "  synced: $consumer_rel"
        SYNCED=$((SYNCED + 1))
      fi
    fi
  done
done

if [[ "$MODE" == "--check" ]]; then
  if [[ $DRIFT -gt 0 ]]; then
    echo ""
    echo "FAIL: $DRIFT consumer(s) drifted from scripts/_shared/. Run: bash scripts/sync-shared-scripts.sh"
    exit 1
  fi
  echo "ok — all shared scripts in sync"
  exit 0
fi

if [[ $SYNCED -eq 0 ]]; then
  echo "ok — all consumers already in sync"
else
  echo "synced $SYNCED file(s) from scripts/_shared/"
fi
